using Microsoft.AspNetCore.Mvc;
using System.Data.SqlClient;
using System.Threading.Tasks;

[ApiController]
[Route("api/[controller]")]
public class UsersController : ControllerBase
{
    private readonly string _connectionString = "your_connection_string_here";

    [HttpGet]
    public async Task<IActionResult> SearchUsersByEmail(string email)
    {
        if (string.IsNullOrEmpty(email))
        {
            return BadRequest("Email query parameter is required.");
        }

        using (SqlConnection connection = new SqlConnection(_connectionString))
        {
            await connection.OpenAsync();

            string sql = "SELECT * FROM Users WHERE Email LIKE @Email";
            SqlCommand command = new SqlCommand(sql, connection);
            command.Parameters.AddWithValue("@Email", $"%{email}%");

            SqlDataReader reader = await command.ExecuteReaderAsync();
            var users = new List<User>();

            while (await reader.ReadAsync())
            {
                users.Add(new User
                {
                    Id = reader.GetInt32(0),
                    Name = reader.GetString(1),
                    Email = reader.GetString(2)
                });
            }

            return Ok(users);
        }
    }
}

